DOCUMENT();
############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "PCCmacros.pl", "contextForm.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ ($m,$h,$k) = random_subset(3,2..9); $h = -$h; $k = -$k; Context()->noreduce('(-x)-y','(-x)+y'); $f = Formula("$m(x-$h)+$k")->reduce; Context("Point"); Context()->parens->set("[" => {type => "Interval", close => "]"}); Context()->parens->set("{" => {type => "Set", close => "}"}); Context()->parens->set("<" => {type => "Vector", close => ">"}); $p = Point("($h,$k)");
############################################################ # Body ############################################################
BEGIN_PGML A line's equation is given in point-slope form. Identify the slope and the point on the line that is being singled out.
[`y=[$f]`]
[@KeyboardInstructions('Enter the slope here.')@]**
[_]{$m}{5}
[@KeyboardInstructions('Enter the point here.')@]**
[_]{$p}{5}
END_PGML
############################################################ # End Problem ############################################################
